  s.on('init', (data) => {
    myId = data.id;
    // Store stable playerId for reconnect sessions
    if (data.playerId) {
      try { localStorage.setItem(STORAGE_KEY_PLAYER_ID, data.playerId); } catch (_) {}
    }
    gameState = data.state;
