    disposeMeshMap(enemiesMeshes, scene);
    disposeMeshMap(enemyHealthBars, scene);
    disposeMeshMap(telegraphMeshes, scene);
    disposeMeshMap(minionsMeshes, scene);
    disposeMeshMap(lootMeshes, scene, true);
