      // Single-note sound
      const osc = audioCtx.createOscillator();
      osc.type = 'sine';
      osc.frequency.value = config.freq;
      osc.connect(audioCtx.destination);
      osc.start(now);
      osc.stop(now + config.duration);
    }
  } catch (e) {
